const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const query1 = `SELECT COALESCE(status, 'unknown') as status, COUNT(*) as count FROM subscribers WHERE tenant_id = ${esc(tenantId)} GROUP BY status`;
const query2 = `SELECT COALESCE(source, 'unknown') as source, COUNT(*) as count FROM subscribers WHERE tenant_id = ${esc(tenantId)} GROUP BY source`;
const query3 = `SELECT COUNT(*) as count FROM subscribers WHERE tenant_id = ${esc(tenantId)} AND created_at >= NOW() - INTERVAL '30 days'`;
const query4 = `SELECT COUNT(*) as count FROM subscriber_lists WHERE tenant_id = ${esc(tenantId)}`;
const query5 = `SELECT COUNT(*) as count FROM subscribers WHERE tenant_id = ${esc(tenantId)}`;

return { queries: [query1, query2, query3, query4, query5] };

const byStatusData = $('05. Query By Status').first().json || [];
const bySourceData = $('06. Query By Source').first().json || [];
const newLast30Data = $('07. Query New 30 Days').first().json || [];
const listsCountData = $('08. Query Lists Count').first().json || [];
const totalCountData = $('09. Query Total Count').first().json || [];

const byStatus = {};
if (Array.isArray(byStatusData)) {
  byStatusData.forEach(row => {
    byStatus[row.status] = parseInt(row.count) || 0;
  });
}

const bySource = {};
if (Array.isArray(bySourceData)) {
  bySourceData.forEach(row => {
    bySource[row.source] = parseInt(row.count) || 0;
  });
}

const newLast30Days = (Array.isArray(newLast30Data) && newLast30Data.length > 0) ? parseInt(newLast30Data[0].count) || 0 : 0;
const totalLists = (Array.isArray(listsCountData) && listsCountData.length > 0) ? parseInt(listsCountData[0].count) || 0 : 0;
const total = (Array.isArray(totalCountData) && totalCountData.length > 0) ? parseInt(totalCountData[0].count) || 0 : 0;

const formatted = {
  stats: {
    total: total,
    byStatus: {
      active: byStatus['active'] || 0,
      unsubscribed: byStatus['unsubscribed'] || 0,
      bounced: byStatus['bounced'] || 0
    },
    bySource: {
      lead: bySource['lead'] || 0,
      client: bySource['client'] || 0,
      contact_form: bySource['contact_form'] || 0,
      manual: bySource['manual'] || 0,
      import_csv: bySource['import_csv'] || 0
    },
    newLast30Days: newLast30Days,
    totalLists: totalLists
  }
};

return formatted;
